/* ----- background/storage.js ----- */
/** 全家桶 manifest 合併後的必填 host_permissions，不可 chrome.permissions.remove */
const SUITE_REQUIRED_HOST_ORIGINS = new Set([
  "file:///*",
  "https://*.youtube.com/*",
]);

// chrome.storage.sync.clear()
// chrome.permissions.getAll((p) => chrome.permissions.remove({origins: p.origins}))

md.storage = ({compilers}) => {

  var defaults = md.storage.defaults(compilers)

  var state = {}
  var api = {defaults, state, set, ready: false}

  async function set (options, meta) {
    await chrome.storage.sync.set(options)
    Object.assign(state, options)
    if (meta && meta.skipSuitePersist) return
    if (
      typeof globalThis.__mdMarkdownSuite?.persistPatch === 'function' &&
      options &&
      typeof options === 'object'
    ) {
      try {
        await globalThis.__mdMarkdownSuite.persistPatch(options)
      } catch (_) {
        /* noop */
      }
    }
  }

  chrome.storage.sync.get((res) => {
    md.storage.bug(res)

    Object.assign(state, JSON.parse(JSON.stringify(
      !Object.keys(res).length ? defaults : res)))

    if (typeof globalThis.__mdMarkdownSuite?.getSettingsSeed === 'function') {
      var seed = globalThis.__mdMarkdownSuite.getSettingsSeed()
      if (seed && typeof seed === 'object') {
        if (seed.origins && typeof seed.origins === 'object') {
          state.origins = Object.assign({}, seed.origins, state.origins || {})
          if (!state.origins['file://'] && seed.origins['file://']) {
            state.origins['file://'] = seed.origins['file://']
          }
        }
        if (!state.compiler && seed.compiler) {
          state.compiler = seed.compiler
        }
        if (!state.theme && seed.theme) {
          state.theme = seed.theme
        }
      }
    }

    // in case of new providers from the compilers branch
    Object.keys(compilers).forEach((compiler) => {
      if (!state[compiler]) {
        state[compiler] = compilers[compiler].defaults
      }
    })

    md.storage.normalizeState(state, defaults, compilers)

    try {
      md.storage.migrations(state)
    } catch (err) {
      console.error('[markdown-viewer] storage migrations failed, resetting to defaults:', err)
      Object.assign(state, JSON.parse(JSON.stringify(defaults)))
      md.storage.normalizeState(state, defaults, compilers)
      md.storage.migrations(state)
    }

    md.storage.ensureOrigins(state, defaults)

    api.ready = true
    set(state, { skipSuitePersist: true })
  })

  return api
}

md.storage.normalizeState = (state, defaults, compilers) => {
  if (!state.content || typeof state.content !== 'object' || Array.isArray(state.content)) {
    state.content = JSON.parse(JSON.stringify(defaults.content))
  }
  if (!state.themes || typeof state.themes !== 'object' || Array.isArray(state.themes)) {
    state.themes = JSON.parse(JSON.stringify(defaults.themes))
  }
  if (!state.settings || typeof state.settings !== 'object' || Array.isArray(state.settings)) {
    state.settings = JSON.parse(JSON.stringify(defaults.settings))
  }
  if (!state.custom || typeof state.custom !== 'object' || Array.isArray(state.custom)) {
    state.custom = JSON.parse(JSON.stringify(defaults.custom))
  }
  if (!state.origins || typeof state.origins !== 'object' || Array.isArray(state.origins)) {
    state.origins = JSON.parse(JSON.stringify(defaults.origins))
  }
  Object.keys(compilers || {}).forEach((compiler) => {
    if (!state[compiler] || typeof state[compiler] !== 'object' || Array.isArray(state[compiler])) {
      state[compiler] = JSON.parse(JSON.stringify(
        compilers[compiler].defaults || defaults[compiler] || {},
      ))
    }
  })
}

md.storage.ensureOrigins = (state, defaults) => {
  if (!state.origins || typeof state.origins !== 'object') {
    state.origins = {}
  }
  Object.keys(defaults.origins || {}).forEach((key) => {
    if (!state.origins[key]) {
      state.origins[key] = JSON.parse(JSON.stringify(defaults.origins[key]))
    }
  })
}

md.storage.defaults = (compilers) => {
  var match = '\\.(?:markdown|mdown|mkdn|md|mkd|mdwn|mdtxt|mdtext|text)(?:#.*|\\?.*)?$'

  var defaults = {
    theme: 'github',
    compiler: 'markdown-it',
    raw: false,
    match,
    themes: {
      width: 'auto',
    },
    content: {
      autoreload: false,
      emoji: false,
      mathjax: false,
      mermaid: false,
      syntax: true,
      toc: false,
    },
    origins: {
      'file://': {
        header: true,
        path: true,
        match,
      }
    },
    settings: {
      icon: 'default',
      theme: 'light',
    },
    custom: {
      theme: '',
      color: 'auto',
    }
  }

  Object.keys(compilers).forEach((compiler) => {
    defaults[compiler] = compilers[compiler].defaults
  })

  return defaults
}

md.storage.bug = (res) => {
  // 僅清除「可選」來源權限；勿移除 manifest host_permissions（會拋錯）
  chrome.permissions.getAll((permissions) => {
    if (!permissions.origins?.length) return
    var origins = Object.keys(res.origins || {})
    var toRemove = permissions.origins.filter((origin) => {
      if (SUITE_REQUIRED_HOST_ORIGINS.has(origin)) return false
      return origins.indexOf(origin.slice(0, -2)) === -1
    })
    if (!toRemove.length) return
    chrome.permissions.remove({ origins: toRemove }, () => {
      if (chrome.runtime.lastError) {
        console.warn(
          "[markdown-viewer] storage.bug permissions.remove:",
          chrome.runtime.lastError.message,
        )
      }
    })
  })
}

md.storage.migrations = (state) => {
  // v3.6 -> v3.7
  if (typeof state.origins['file://'] === 'object') {
    state.origins['file://'].csp = false
  }
  if (typeof state.theme === 'string') {
    state.theme = {
      name: state.theme,
      url: chrome.runtime.getURL(`plugins/markdown-viewer/themes/${state.theme}.css`)
    }
  }
  if (state.themes === undefined) {
    state.themes = []
  }
  if (state.marked.tables !== undefined) {
    delete state.marked.tables
  }
  // v3.9 -> v4.0
  if (state.remark.commonmark !== undefined) {
    delete state.remark.commonmark
  }
  if (state.remark.pedantic !== undefined) {
    delete state.remark.pedantic
  }
  if (state.content.mermaid === undefined) {
    state.content.mermaid = false
  }
  if (state.themes === undefined || state.themes instanceof Array) {
    state.themes = {wide: false}
  }
  if (typeof state.theme === 'object') {
    state.theme = state.theme.name
  }
  // v4.0 -> v5.0
  Object.keys(state.origins).forEach((origin) => {
    state.origins[origin].csp = false
    state.origins[origin].encoding = ''
  })
  if (state.marked.smartLists !== undefined) {
    delete state.marked.smartLists
  }
  if (state.content.syntax === undefined) {
    state.content.syntax = true
  }
  if (state.themes.wide !== undefined) {
    if (state.themes.wide) {
      state.themes.width = 'full'
    }
    delete state.themes.wide
  }
  if (state.icon === undefined) {
    state.icon = false
  }
  if (state.remark.footnotes !== undefined) {
    delete state.remark.footnotes
  }
  // v5.0 -> v5.1
  if (state.header !== null) {
    Object.keys(state.origins).forEach((origin) => {
      state.origins[origin].header = true
      state.origins[origin].path = true
      delete state.origins[origin].csp
      delete state.origins[origin].encoding
    })
    state.header = null
  }
  if (state.content.scroll !== undefined) {
    delete state.content.scroll
  }
  if (state.settings === undefined) {
    state.settings = {
      icon: state.icon === true ? 'light' : 'dark',
      theme: 'light'
    }
  }
  // v5.1 -> v5.2
  if (state['markdown-it'] && state['markdown-it'].abbr === undefined) {
    Object.assign(state['markdown-it'], {
      abbr: false,
      attrs: false,
      cjk: false,
      deflist: false,
      footnote: false,
      ins: false,
      mark: false,
      sub: false,
      sup: false,
      tasklists: false,
    })

  }
  if (state.marked.linkify === undefined) {
    Object.assign(state.marked, {
      linkify: true,
    })
    delete state.marked.sanitize
  }
  // v5.2 -> v5.3
  if (state.custom === undefined) {
    state.custom = {
      theme: '',
      color: 'auto'
    }
  }
}

;

/* ----- background/webrequest.js ----- */

md.webrequest = ({storage: {state}}) => {

  var permissions = ['webRequest']

  var filter = {
    urls: ['<all_urls>'],
    types: ['main_frame', 'sub_frame']
  }

  var onCompleted = ({ip, tabId}) => {
    if (ip && ip !== '127.0.0.1' && ip !== '::1') {
      setTimeout(() => {
        chrome.tabs.sendMessage(tabId, {message: 'autoreload'})
      }, 500)
    }
  }

  var webrequest = () => {
    if (state.content.autoreload && !chrome.webRequest) {
      // request permissions
      chrome.permissions.request({permissions}, () => {
        // add listener
        chrome.webRequest.onCompleted.addListener(onCompleted, filter)
      })
    }
    else if (!state.content.autoreload && chrome.webRequest) {
      chrome.webRequest.onCompleted.removeListener(onCompleted)
      chrome.permissions.contains({ permissions }, (granted) => {
        if (!granted) return
        chrome.permissions.remove({ permissions }, () => {
          if (chrome.runtime.lastError) {
            console.warn(
              "[markdown-viewer] webrequest permissions.remove:",
              chrome.runtime.lastError.message,
            )
          }
        })
      })
    }
  }

  // init
  if (chrome.webRequest) {
    chrome.webRequest.onCompleted.addListener(onCompleted, filter)
  }

  return webrequest
}

;

/* ----- background/detect.js ----- */

md.detect = ({storage: {state}, inject}) => {

  var onwakeup = true

  var ff = (id, info, done) => {
    if (chrome.runtime.getBrowserInfo === undefined) {
      // chrome
      done('load')
    }
    else {
      var manifest = chrome.runtime.getManifest()
      if (manifest.browser_specific_settings && manifest.browser_specific_settings.gecko) {
        if (!info.url) {
          done('noop')
        }
        else {
          chrome.tabs.sendMessage(id, {message: 'ping'})
            .then(() => done('noop'))
            .catch(() => done('load'))
        }
      }
      else {
        done('load')
      }
    }
  }

  var probeTab = (id) => {
    ff(id, {}, (action) => {
      if (action === 'noop') {
        return
      }
      chrome.scripting.executeScript({
        target: {tabId: id},
        func: () =>
          JSON.stringify({
            url: window.location.href,
            header: document.contentType,
            loaded: !!(window.__mdViewerMounted || window.__mdViewerMounting),
          })
      }, (res) => {
          if (chrome.runtime.lastError) {
            // origin not allowed
            return
          }

          try {
            var win = JSON.parse(res[0].result)
            if (!win) {
              return
            }
          }
          catch (err) {
            // JSON parse error
            return
          }

          if (win.loaded) {
            // anchor
            return
          }

          if (detect(win.header, win.url)) {
            if (onwakeup && chrome.webRequest) {
              onwakeup = false
              chrome.tabs.reload(id)
            }
            else {
              inject(id)
            }
          }
        })
    })
  }

  var tab = (id, info, tab) => {
    if (info.status !== 'loading' && info.status !== 'complete') {
      return
    }
    probeTab(id)
  }

  var detect = (content, url) => {
    var location = new URL(url)

    var origin =
      state.origins[location.origin] ||

      state.origins[location.protocol + '//'] ||
      state.origins[location.protocol + '//' + location.hostname] ||
      state.origins[location.protocol + '//' + location.host] ||
      state.origins[location.protocol + '//*.' + location.hostname.replace(/^[^.]+\.(.*)/, '$1')] ||
      state.origins[location.protocol + '//*.' + location.host.replace(/^[^.]+\.(.*)/, '$1')] ||

      state.origins['*://' + location.hostname] ||
      state.origins['*://' + location.host] ||
      state.origins['*://*.' + location.hostname.replace(/^[^.]+\.(.*)/, '$1')] ||
      state.origins['*://*.' + location.host.replace(/^[^.]+\.(.*)/, '$1')] ||

      state.origins['*://*']

    var pathMatch = origin && origin.path && origin.match && new RegExp(origin.match).test(location.href)
    var mdContent = /\btext\/(?:(?:(?:x-)?markdown)|plain)\b/i.test(content)
    // file:// 等情境下 document.contentType 常為空字串，仍應依副檔名匹配
    var looseContent = !content || content === 'application/octet-stream'

    return (
      (origin && origin.header && origin.path && pathMatch && (mdContent || looseContent)) ||
      (origin && origin.header && !origin.path && (mdContent || looseContent)) ||
      (origin && origin.path && pathMatch && !origin.header)
        ? origin
        : undefined
    )
  }

  md.detect.isFileMarkdownUrl = (url) => {
    try {
      var location = new URL(url)
      if (!/^file:/i.test(location.protocol)) return false
      var ext = '\\.(?:markdown|mdown|mkdn|md|mkd|mdwn|mdtxt|mdtext|text)(?:#.*|\\?.*)?$'
      return new RegExp(ext, 'i').test(location.pathname + location.search + location.hash)
    } catch (err) {
      return false
    }
  }

  return {tab, probeTab, matches: detect}
}

;

/* ----- background/inject.js ----- */

md.inject = ({storage: {state, defaults}}) => {
  var injectingTabs = new Set()

  return (id) => {
  if (injectingTabs.has(id)) return
  injectingTabs.add(id)

  var content = (state && state.content) || (defaults && defaults.content) || {syntax: true}
  var themes = (state && state.themes) || (defaults && defaults.themes) || {width: 'auto'}
  var settings = (state && state.settings) || (defaults && defaults.settings) || {icon: 'default'}
  var custom = (state && state.custom) || (defaults && defaults.custom) || {theme: '', color: 'auto'}

  var scriptFiles = [
    'plugins/markdown-viewer/vendor/mithril.min.js',
    content.syntax && ['plugins/markdown-viewer/vendor/prism.min.js', 'plugins/markdown-viewer/vendor/prism-autoloader.min.js', 'plugins/markdown-viewer/content/prism.js'],
    content.emoji && 'plugins/markdown-viewer/content/emoji.js',
    content.mermaid && ['plugins/markdown-viewer/vendor/mermaid.min.js', 'plugins/markdown-viewer/vendor/panzoom.min.js', 'plugins/markdown-viewer/content/mermaid.js'],
    content.mathjax && ['plugins/markdown-viewer/content/mathjax.js', 'plugins/markdown-viewer/vendor/mathjax/tex-mml-chtml.js'],
    'plugins/markdown-viewer/content/index.js',
    'plugins/markdown-viewer/content/scroll.js',
    content.autoreload && 'plugins/markdown-viewer/content/autoreload.js',
  ].filter(Boolean).flat()

  chrome.scripting.executeScript({
    target: {tabId: id},
    args: [{
      theme: state.theme || (defaults && defaults.theme) || 'github',
      raw: !!state.raw,
      themes: themes,
      content: content,
      compiler: state.compiler || (defaults && defaults.compiler) || 'markdown-it',
      custom: custom,
      icon: settings.icon,
    }],
    func: (_args) => {
      args = _args
    },
    injectImmediately: true
  }, () => {
    if (chrome.runtime.lastError) {
      injectingTabs.delete(id)
      return
    }

    chrome.scripting.insertCSS({
      target: {tabId: id},
      files: [
        'plugins/markdown-viewer/content/index.css',
        'plugins/markdown-viewer/content/themes.css',
      ]
    }, () => {
      if (chrome.runtime.lastError) {
        injectingTabs.delete(id)
        return
      }

      chrome.scripting.executeScript({
        target: {tabId: id},
        files: scriptFiles,
        injectImmediately: true
      }, () => {
        injectingTabs.delete(id)
      })
    })
  })

  }
}

;

/* ----- background/messages.js ----- */

md.messages = ({storage, compilers, mathjax, xhr, webrequest, icon}) => {

  var defaults = storage.defaults
  var state = storage.state
  var set = storage.set

  function popupPayload(pending) {
    var compilerKeys = Object.keys(compilers)
    var id = (state.compiler && compilers[state.compiler])
      ? state.compiler
      : compilerKeys[0]
    var entry = id && compilers[id]
    var options = entry
      ? (state[id] || entry.defaults || {})
      : {}
    var description = entry ? entry.description : {}
    var settingsTheme = (state.settings && state.settings.theme)
      || (defaults.settings && defaults.settings.theme)
      || 'light'
    return Object.assign({}, state, {
      pending: Boolean(pending),
      compiler: id || defaults.compiler,
      options: options,
      description: description,
      compilers: compilerKeys,
      themes: state.themes || defaults.themes,
      content: state.content || defaults.content,
      theme: state.theme || defaults.theme,
      settings: {theme: settingsTheme},
    })
  }

  return (req, sender, sendResponse) => {
    if (req && typeof req.type === 'string' && req.type.startsWith('suite:')) {
      return false;
    }

    // content
    if (req.message === 'markdown') {
      function compileAndRespond() {
        if (globalThis.__mdMarkdownSuite && !globalThis.__mdMarkdownSuite.isEnabled()) {
          sendResponse({message: 'html', html: '', error: 'disabled'})
          return
        }
        try {
          var markdown = req.markdown
          var contentOpts = state.content || defaults.content || {}
          var compilerId = (req.compiler && compilers[req.compiler])
            ? req.compiler
            : state.compiler
          var compiler = compilers[compilerId]
          if (!compiler) {
            sendResponse({message: 'html', html: '', error: 'no-compiler'})
            return
          }

          if (contentOpts.mathjax) {
            var jax = mathjax()
            markdown = jax.tokenize(markdown)
          }

          var html = compiler.compile(markdown)

          if (contentOpts.mathjax) {
            html = jax.detokenize(html)
          }

          sendResponse({message: 'html', html})
        } catch (err) {
          console.error('[markdown-viewer] compile error:', err)
          sendResponse({message: 'html', html: '', error: String(err && err.message || err)})
        }
      }

      if (storage.ready) {
        compileAndRespond()
        return true
      }

      var waited = 0
      var waitReady = setInterval(function () {
        waited += 25
        if (!storage.ready && waited < 3000) return
        clearInterval(waitReady)
        if (!storage.ready) {
          sendResponse({message: 'html', html: '', error: 'not-ready'})
          return
        }
        compileAndRespond()
      }, 25)
      return true
    }
    else if (req.message === 'autoreload') {
      xhr.get(req.location, (err, body) => {
        sendResponse({err, body})
      })
    }
    else if (req.message === 'prism') {
      chrome.scripting.executeScript({
        target: {tabId: sender.tab.id},
        files: [
          `plugins/markdown-viewer/vendor/prism/prism-${req.language}.min.js`,
        ],
        injectImmediately: true
      }, sendResponse)
    }
    else if (req.message === 'mathjax') {
      chrome.scripting.executeScript({
        target: {tabId: sender.tab.id},
        files: [
          `plugins/markdown-viewer/vendor/mathjax/extensions/${req.extension}.js`,
        ],
        injectImmediately: true
      }, sendResponse)
    }

    // popup
    else if (req.message === 'popup') {
      if (!storage.ready) {
        sendResponse(popupPayload(true))
      }
      else {
        var compilerKeys = Object.keys(compilers)
        var id = (state.compiler && compilers[state.compiler])
          ? state.compiler
          : compilerKeys[0]
        if (!id || !compilers[id]) {
          sendResponse(popupPayload(false))
        }
        else {
          sendResponse(popupPayload(false))
        }
      }
    }
    else if (req.message === 'popup.theme') {
      set({theme: req.theme})
      notifyContent({message: 'theme', theme: req.theme})
      sendResponse()
    }
    else if (req.message === 'popup.raw') {
      set({raw: req.raw})
      notifyContent({message: 'raw', raw: req.raw})
      sendResponse()
    }
    else if (req.message === 'popup.themes') {
      set({themes: req.themes})
      notifyContent({message: 'themes', themes: req.themes})
      sendResponse()
    }
    else if (req.message === 'popup.defaults') {
      var options = Object.assign({}, defaults)
      options.origins = state.origins
      set(options)
      notifyContent({message: 'reload'})
      sendResponse()
    }
    else if (req.message === 'popup.compiler.name') {
      set({compiler: req.compiler})
      notifyContent({message: 'reload'})
      sendResponse()
    }
    else if (req.message === 'popup.compiler.options') {
      set({[req.compiler]: req.options})
      notifyContent({message: 'reload'})
      sendResponse()
    }
    else if (req.message === 'popup.content') {
      set({content: req.content})
      notifyContent({message: 'reload'})
      webrequest()
      sendResponse()
    }
    else if (req.message === 'popup.advanced') {
      if (globalThis.__mdMarkdownSuite) {
        var optionsBase = chrome.runtime.getURL('src/options/options.html')
        chrome.tabs.create({
          url: optionsBase + '?plugin=markdown-viewer',
        })
      } else if (/Firefox/.test(navigator.userAgent)) {
        chrome.management.getSelf((extension) => {
          chrome.tabs.create({url: extension.optionsUrl})
        })
      } else {
        chrome.runtime.openOptionsPage()
      }
      sendResponse()
    }

    // origins view
    else if (req.message === 'options.origins') {
      sendResponse({
        origins: state.origins,
        match: state.match,
      })
    }
    // origins options
    else if (req.message === 'origin.add') {
      state.origins[req.origin] = {
        header: true,
        path: true,
        match: defaults.match,
      }
      set({origins: state.origins})
      sendResponse()
    }
    else if (req.message === 'origin.remove') {
      delete state.origins[req.origin]
      set({origins: state.origins})
      webrequest()
      sendResponse()
    }
    else if (req.message === 'origin.update') {
      state.origins[req.origin] = req.options
      set({origins: state.origins})
      webrequest()
      sendResponse()
    }

    // settings view
    else if (req.message === 'options.settings') {
      sendResponse(state.settings)
    }
    // settings options
    else if (req.message === 'options.icon') {
      set({settings: req.settings})
      icon()
      sendResponse()
    }
    else if (req.message === 'options.theme') {
      set({settings: req.settings})
      sendResponse()
    }
    else if (req.message === 'custom.get') {
      sendResponse(state.custom)
    }
    else if (req.message === 'custom.set') {
      set({custom: req.custom}).then(sendResponse).catch((err) => {
        if (/QUOTA_BYTES_PER_ITEM quota exceeded/.test(err.message)) {
          sendResponse({error: 'Minified theme exceeded 8KB in size!'})
        }
      })
    }
    else {
      return false
    }

    return true
  }

  function notifyContent (req, res) {
    chrome.tabs.query({active: true, currentWindow: true}, (tabs) => {
      chrome.tabs.sendMessage(tabs[0].id, req, res)
    })
  }
}

;

/* ----- background/mathjax.js ----- */

md.mathjax = () => {

  var delimiters = new RegExp([
    /\$\$[^`]*?\$\$/,
    /\\\([^`]*?\\\)/,
    /\\\[[^`]*?\\\]/,
    /\\begin\{.*?\}[^`]*?\\end\{.*?\}/,
    /\$[^`\n]*?\$/,
  ]
  .map((regex) => `(?:${regex.source})`).join('|'), 'gi')

  var escape = (math) =>
    math.replace(/[<>&]/gi, (symbol) =>
      symbol === '>' ? '&gt;' :
      symbol === '<' ? '&lt;' :
      symbol === '&' ? '&amp;': null
    )

  var ctor = (map = {}) => ({
    tokenize: (markdown) =>
      markdown.replace(delimiters, (str, offset) => (
        map[offset] = str,
        `?${offset}?`
      ))
    ,
    detokenize: (html) =>
      Object.keys(map)
        .reduce((html, offset) =>
          html = html.replace(`?${offset}?`, () => escape(map[offset])),
          html
        )
  })

  return Object.assign(ctor, {delimiters, escape})
}

;

/* ----- background/xhr.js ----- */

md.xhr = () => {

  var get = (url, done) => {
    ;(async () => {
      await new Promise(async (resolve, reject) => {
        try {
          var res = await fetch(url + '?preventCache=' + Date.now())
          done(null, await res.text())
        }
        catch (err) {
          done(err)
        }
      })
    })()
  }

  return {get}
}

;

/* ----- background/icon.js ----- */

md.icon = ({storage: {state}}) => () => {
  if (globalThis.__mdMarkdownSuite) {
    return;
  }
  setTimeout(() =>
    chrome.action.setIcon({
      path: [16, 19, 38, 48, 128].reduce((all, size) => (
        all[size] = `plugins/markdown-viewer/icons/${state.settings.icon}/${size}x${size}.png`,
        all
      ), {})
    })
  , 100)
}

;

/* ----- background/suite-init.js ----- */
md.bootstrapMarkdownSuiteBackground = function () {
  if (globalThis.__mdMarkdownSuiteInit) return
  globalThis.__mdMarkdownSuiteInit = true

  var storage = md.storage(md);
  var injectRaw = md.inject({ storage });
  var inject = function (id) {
    if (storage.ready) {
      injectRaw(id);
      return;
    }
    var waitReady = setInterval(function () {
      if (!storage.ready) return;
      clearInterval(waitReady);
      injectRaw(id);
    }, 30);
  };
  var detectApi = md.detect({ storage, inject });
  var webrequest = md.webrequest({ storage });
  var mathjax = md.mathjax();
  var xhr = md.xhr();
  var icon = md.icon({ storage });

  var compilers = Object.keys(md.compilers).reduce(function (all, compiler) {
    all[compiler] = md.compilers[compiler]({ storage });
    return all;
  }, {});

  var messages = md.messages({
    storage,
    compilers,
    mathjax,
    xhr,
    webrequest,
    icon,
  });

  function suiteEnabled() {
    return !globalThis.__mdMarkdownSuite || globalThis.__mdMarkdownSuite.isEnabled();
  }

  function scanOpenTabs() {
    if (!suiteEnabled()) return;
    chrome.tabs.query({}, function (tabs) {
      tabs.forEach(function (tab) {
        if (tab.id) detectApi.probeTab(tab.id);
      });
    });
  }

  function injectFromPageReady(req, sender, sendResponse) {
    if (!suiteEnabled()) {
      sendResponse({ ok: false, reason: 'disabled' })
      return
    }
    var tabId = sender.tab && sender.tab.id
    if (!tabId || !req.url) {
      sendResponse({ ok: false })
      return
    }
    if (md.detect.isFileMarkdownUrl(req.url) || detectApi.matches(req.header, req.url)) {
      inject(tabId)
      sendResponse({ ok: true, injected: true })
    } else {
      detectApi.probeTab(tabId)
      sendResponse({ ok: true, probed: true })
    }
  }

  chrome.tabs.onUpdated.addListener(function (id, info, tab) {
    if (!suiteEnabled()) return;
    detectApi.tab(id, info, tab);
  });

  chrome.runtime.onMessage.addListener(messages);

  chrome.runtime.onMessage.addListener(function (req, sender, sendResponse) {
    if (req.message === 'md:pageReady') {
      if (storage.ready) {
        injectFromPageReady(req, sender, sendResponse)
      } else {
        var waitReady = setInterval(function () {
          if (!storage.ready) return
          clearInterval(waitReady)
          injectFromPageReady(req, sender, sendResponse)
        }, 30)
      }
      return true
    }
    if (req.message === 'md:rescanTabs') {
      if (!suiteEnabled()) {
        sendResponse({ ok: false })
        return true
      }
      scanOpenTabs()
      chrome.tabs.query({ active: true, currentWindow: true }, function (tabs) {
        var tab = tabs && tabs[0]
        if (tab && tab.id && md.detect.isFileMarkdownUrl(tab.url || '')) {
          chrome.tabs.reload(tab.id)
        }
      })
      sendResponse({ ok: true })
      return true
    }
    return false
  })

  var readyPoll = setInterval(function () {
    if (!storage.ready) return;
    clearInterval(readyPoll);
    scanOpenTabs();
  }, 50);

  globalThis.__mdMarkdownScanTabs = scanOpenTabs;
  globalThis.__mdMarkdownReady = true;

  icon();
}

;

export function bootstrapMarkdownSuiteBackground() {
  if (typeof md === "undefined" || typeof md.bootstrapMarkdownSuiteBackground !== "function") {
    throw new Error("[markdown-viewer] incomplete bundle — run bundle-markdown-sw.mjs");
  }
  md.bootstrapMarkdownSuiteBackground();
}
